import React from "react";
import { Link } from "react-router-dom";
import { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import backButton from "./backButton.png";
import Tabbar from "./tabbar.js";

function Station() {
  const { id } = useParams();

  const stations = [
    { id: 1, adress: "Ул. Леонардо да Винчи, д. 1", rating: 100, price: 50 },
    { id: 2, adress: "Ул. Галилео Галилея, д. 2", rating: 50, price: 40 },
    { id: 3, adress: "Ул. Достоевского, д. 3", rating: 130, price: 80 },
    { id: 4, adress: "Ул. Джордано Бруно, д. 4", rating: 200, price: 70 },
    { id: 5, adress: "Ул. Коперника, д. 5", rating: 1200, price: 120 },
  ];

  const navigate = useNavigate();

  return (
    <div>
      <h1>Станция</h1>
      <div className="buttons">
        <img src={backButton} onClick={() => navigate(-1)} />
      </div>
      <p>Адрес: {stations[id - 1]["adress"]}</p>
      <p>Рейтинг: {stations[id - 1]["rating"]}</p>
      <p>Стоимость: {stations[id - 1]["price"]} рублей / минута</p>
      <Tabbar />
    </div>
  );
}

export default Station;
