import React from "react";
import { Link } from "react-router-dom";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import backButton from "./backButton.png";
import stationInfo from "./stationInfo.png";
import markerDefault from "./markerDefault.png";
import { YMaps, Map, Placemark } from "@pbe/react-yandex-maps";
import { BottomSheet } from "react-spring-bottom-sheet";
import "react-spring-bottom-sheet/dist/style.css";
import { useState } from "react";
import Station from "./station.js";
import Tabbar from "./tabbar.js";

function MapY() {
  const [open, setOpen] = useState(false);

  const navigate = useNavigate();

  const defaultState = {
    center: [43.237163, 76.945654],
    zoom: 12,
  };

  function onDismiss() {
    setOpen(false);
  }

  return (
    <div className="mapContainer">
      <YMaps>
        <Map
          defaultState={defaultState}
          width="100%"
          height="100%"
          className="mapAll"
        >
          <Placemark geometry={[55.684758, 37.738521]} />
          <Placemark
            geometry={[43.237169, 76.945653]}
            options={{
              iconLayout: "default#image",
              iconImageHref: `${markerDefault}`,
              iconImageSize: [50, 50],
            }}
            onClick={() => setOpen(true)}
          />
          <Placemark
            geometry={[43.299269, 76.915653]}
            options={{
              iconLayout: "default#image",
              iconImageHref: `${markerDefault}`,
              iconImageSize: [50, 50],
            }}
            onClick={() => setOpen(true)}
          />
        </Map>
      </YMaps>

      <BottomSheet
        open={open}
        onDismiss={onDismiss}
        snapPoints={({ headerHeight, footerHeight }) => [400]}
      >
        <img src={stationInfo} />
      </BottomSheet>
      <Tabbar />
    </div>
  );
}
export default MapY;
